console.log("JavaScript文件加载成功！");

// 确保DOM加载完成
document.addEventListener("DOMContentLoaded", function() {
    console.log("DOM加载完成，开始初始化事件监听器！");
    
    // 获取按钮和消息元素
    var greetButton = document.getElementById('greetButton');
    var greetMessage = document.getElementById('greetMessage');
    
    console.log("按钮元素:", greetButton);
    console.log("消息元素:", greetMessage);
    
    // 为按钮添加点击事件
    if (greetButton) {
        console.log("找到按钮，添加点击事件监听器！");
        greetButton.addEventListener('click', function() {
            console.log("按钮被点击！");
            
            // 生成问候消息
            var messages = [
                '你好！欢迎使用Solo Trae Web Code！',
                '很高兴见到你！',
                '祝你学习愉快！',
                'Solo Trae是你的编程助手！',
                '加油，你可以的！'
            ];
            
            // 随机选择一条消息
            var randomMessage = messages[Math.floor(Math.random() * messages.length)];
            console.log("生成的消息:", randomMessage);
            
            // 显示消息
            greetMessage.textContent = randomMessage;
            greetMessage.style.display = 'block';
            
            // 添加动画效果
            greetMessage.style.opacity = '0';
            greetMessage.style.transition = 'opacity 0.5s ease';
            
            setTimeout(function() {
                greetMessage.style.opacity = '1';
                console.log("消息显示动画完成！");
            }, 100);
            
            // 3秒后隐藏消息
            setTimeout(function() {
                greetMessage.style.opacity = '0';
                setTimeout(function() {
                    greetMessage.style.display = 'none';
                    console.log("消息隐藏完成！");
                }, 500);
            }, 3000);
        });
    } else {
        console.error("未找到按钮元素！");
    }
    
    // 添加页面加载动画
    var sections = document.querySelectorAll('.section');
    console.log("找到的区块数量:", sections.length);
    
    sections.forEach(function(section, index) {
        section.style.opacity = '0';
        section.style.transform = 'translateY(20px)';
        section.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
        
        setTimeout(function() {
            section.style.opacity = '1';
            section.style.transform = 'translateY(0)';
        }, 100 * (index + 1));
    });
});